-- Seed real Lviv cycling accident data (source: Lviv Open Data, 2017-2024).
-- 256 records, is_actual = TRUE to distinguish from synthetic ML training data.
-- Run once after 005_add_is_actual.sql: SELECT seed_csv_data();

CREATE OR REPLACE FUNCTION public.seed_csv_data()
RETURNS TEXT
LANGUAGE plpgsql SECURITY DEFINER AS $$
DECLARE
  inserted INT;
BEGIN
  ON CONFLICT DO NOTHING;

  GET DIAGNOSTICS inserted = ROW_COUNT;
  RETURN format('Seeded %s Lviv accident records (is_actual=TRUE)', inserted);
END;
$$;
